import React from 'react';
import { PokemonWithSpecies } from '../hooks/usePokemon';

interface PokemonCardProps {
  pokemon: PokemonWithSpecies;
  onClick: (pokemon: PokemonWithSpecies) => void;
}

const PokemonCard: React.FC<PokemonCardProps> = ({ pokemon, onClick }) => {
  const { pokemon: p } = pokemon;

  const typeColors: Record<string, string> = {
    normal: 'bg-gray-400',
    fire: 'bg-red-500',
    water: 'bg-blue-500',
    electric: 'bg-yellow-400',
    grass: 'bg-green-500',
    ice: 'bg-cyan-400',
    fighting: 'bg-red-700',
    poison: 'bg-purple-500',
    ground: 'bg-yellow-600',
    flying: 'bg-indigo-400',
    psychic: 'bg-pink-500',
    bug: 'bg-lime-500',
    rock: 'bg-yellow-700',
    ghost: 'bg-purple-700',
    dragon: 'bg-indigo-600',
    dark: 'bg-gray-800',
    steel: 'bg-gray-600',
    fairy: 'bg-pink-400',
    unknown: 'bg-gray-400',
  };

  const totalStats = p.stats.reduce((sum, stat) => sum + stat.base_stat, 0);

  return (
    <div
      className="bg-white rounded-lg shadow-md p-4 cursor-pointer hover:shadow-lg transition-shadow duration-200"
      onClick={() => onClick(pokemon)}
    >
      <div className="flex items-center space-x-4">
        <div className="flex-shrink-0">
          <img
            src={p.sprites.front_default}
            alt={p.name}
            className="w-16 h-16 object-contain"
            onError={(e) => {
              (e.target as HTMLImageElement).src = 'https://via.placeholder.com/64x64?text=?';
            }}
          />
        </div>

        <div className="flex-1 min-w-0">
          <div className="flex items-center space-x-2 mb-1">
            <h3 className="text-lg font-semibold text-gray-900 capitalize truncate">
              {p.name}
            </h3>
            <span className="text-sm text-gray-500">#{p.id.toString().padStart(3, '0')}</span>
          </div>

          <div className="flex flex-wrap gap-1 mb-2">
            {p.types.map((type, index) => (
              <span
                key={index}
                className={`px-2 py-1 text-xs text-white rounded-full ${typeColors[type.type.name] || typeColors.unknown}`}
              >
                {type.type.name}
              </span>
            ))}
          </div>

          <div className="text-sm text-gray-600">
            <div className="flex justify-between">
              <span>Total Stats: {totalStats}</span>
              <span>Height: {p.height / 10}m</span>
            </div>
            <div className="flex justify-between">
              <span>Weight: {p.weight / 10}kg</span>
              <span>Abilities: {p.abilities.length}</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PokemonCard;
